def to_csv(self, include_header: bool = True) -> str:
    import csv
    import io
    output = io.StringIO()
    writer = csv.writer(output)
    if include_header:
        writer.writerow(self.columns)
    for row in self.rows:
        writer.writerow([row.get(col, '') for col in self.columns])
    return output.getvalue()
